import { Registry } from "../../../core/zc-registry";
import { naiveEllipsis } from "../../../utils/zcsvgutils";
import { getExpressionValue, isExpressionType } from "../../parser/parser-helpers";
import { getVal } from "../../../utils/zcutils";

/*
    This function is used to handle text overflow for text mark
    @nodes: d3 selection of nodes
    @prop: property to be handled - here it is `textOverflow`
    @config: configuration object - here it is mark parser of `text` mark
    @cache: cache object - viewflow
*/
export function handleTextOverflow_Mark(nodes, prop, config, cache){
    if(config[prop] === 'ellipsis' || config[prop] === 'clip'){
        let ellipsis = config[prop] === 'ellipsis' ? ".." : "";
        nodes.each(function(d, i){
            let maxWidth = 100,
                maxHeight = 500;
                let __viewflow =  cache ? cache.__tokens__ || cache.cache.__tokens__ : null;
            if(config.maxWidth){
                let isExpression = isExpressionType(config.maxWidth);
                if(isExpression){
                    maxWidth = getExpressionValue(this,[d, i] , config.maxWidth, 'maxWidth', __viewflow);
                }else{
                    maxWidth = getVal(config.maxWidth, [d, i], this);
                }
                
            }
            naiveEllipsis(this, this, this.textContent,  maxWidth, maxHeight, this.getBoundingClientRect(), ellipsis);
        });
    }
}

Registry.setComponent('textMarkOverflow', handleTextOverflow_Mark);